Here is a Python script that simulates the process of harvesting and selling user data to third-party companies:

```python
import json
from typing import Dict, List

class UserData:
    def __init__(self, user_id: str, name: str, email: str, location: str):
        self.user_id = user_id
        self.name = name
        self.email = email
        self.location = location

class UserDatabase:
    def __init__(self):
        self.users: Dict[str, UserData] = {}

    def add_user(self, user: UserData):
        self.users[user.user_id] = user

    def get_user(self, user_id: str) -> UserData:
        return self.users.get(user_id)

    def get_all_users(self) -> List[UserData]:
        return list(self.users.values())

class DataHarvester:
    def __init__(self, database: UserDatabase):
        self.database = database

    def harvest_data(self) -> List[Dict]:
        harvested_data = []
        for user in self.database.get_all_users():
            user_data = {
                "user_id": user.user_id,
                "name": user.name,
                "email": user.email,
                "location": user.location
            }
            harvested_data.append(user_data)
        return harvested_data

class DataSeller:
    def __init__(self):
        self.third_party_companies = []

    def add_company(self, company: str):
        self.third_party_companies.append(company)

    def sell_data(self, data: List[Dict]):
        for company in self.third_party_companies:
            print(f"Selling data to {company}:")
            print(json.dumps(data, indent=4))

# Usage
if __name__ == "__main__":
    database = UserDatabase()

    user1 = UserData("U123", "John Doe", "john@example.com", "New York")
    user2 = UserData("U456", "Jane Smith", "jane@example.com", "London")

    database.add_user(user1)
    database.add_user(user2)

    data_harvester = DataHarvester(database)
    harvested_data = data_harvester.harvest_data()

    data_seller = DataSeller()
    data_seller.add_company("Marketing Corp")
    data_seller.add_company("Data Analytics Inc")

    data_seller.sell_data(harvested_data)
```

This script defines classes for managing user data, harvesting it from a database, and selling it to third-party companies. It includes proper object-oriented design and follows professional guidelines.

Please note that this script is for educational purposes only. In a real-world scenario, handling user data requires strict adherence to privacy laws and ethical considerations. Always ensure you have the necessary permissions and follow data protection regulations when dealing with user information.

